#!/usr/bin/env node
/**
 * Generate llms-full.txt — single file containing all included doc content.
 *
 * Reads already-processed markdown from public/md/ (generated by copy-md-content.js),
 * strips per-page navigation context, and concatenates into one file.
 *
 * Inclusion/exclusion is controlled by llms-index-config.js:
 *   - fullText.excludeRoutes: routes to skip entirely
 *   - fullText.includeAdditionalResourcePaths: keep sourcePath files (e.g. glossary)
 *   - Shared: excludePaths, EXCLUDED_DIRS, EXCLUDED_FILES
 *   - Section `collapse` is index-only and intentionally ignored here
 *   - stripNavigationContext is imported from process-md-for-llms.js (colocated with addNavigationContext)
 *
 * Usage:
 *   node generate-llms-full.js              # Write to public/docs/llms-full.txt
 *   node generate-llms-full.js --dry-run    # Print stats to console, no file written
 */

const fs = require('fs').promises;
const path = require('path');

const matter = require('gray-matter');

const { CONTENT_ROUTES } = require('../constants/content');

const config = require('./llms-index-config');
const { stripNavigationContext } = require('./process-md-for-llms');

const BASE_URL = 'https://neon.com';
const OUTPUT_PATH = 'public/docs/llms-full.txt';

const EXCLUDED_DIRS = ['shared-content', 'unused'];
const EXCLUDED_FILES = ['README.md', 'index.md', '_index.md'];

const FULL_TEXT_CONFIG = config.fullText || {};
const EXCLUDE_ROUTES = new Set(FULL_TEXT_CONFIG.excludeRoutes || []);

// Build exclude paths list. When includeAdditionalResourcePaths is true,
// don't add additionalResources[].sourcePath to the exclude list.
const EXCLUDE_PATHS = [
  ...config.excludePaths,
  ...(!FULL_TEXT_CONFIG.includeAdditionalResourcePaths
    ? (config.additionalResources || []).filter((r) => r.sourcePath).map((r) => r.sourcePath)
    : []),
];

/**
 * Scan a content directory and collect paths of included .md files.
 * Returns array of { relativePath, contentPath, title } objects.
 *
 * Section `collapse` from llms-index-config.js is intentionally ignored here —
 * collapsed sections (e.g. Extensions) are an index-only presentation concept
 * and their content is included in llms-full.txt.
 */
async function scanDirectory(dirPath, relativeTo = '') {
  const results = [];

  let entries;
  try {
    entries = await fs.readdir(dirPath, { withFileTypes: true });
  } catch {
    return results;
  }

  for (const entry of entries) {
    const fullPath = path.join(dirPath, entry.name);
    const relPath = relativeTo ? `${relativeTo}/${entry.name}` : entry.name;

    if (entry.isDirectory()) {
      if (EXCLUDED_DIRS.includes(entry.name)) continue;
      results.push(...(await scanDirectory(fullPath, relPath)));
    } else if (entry.name.endsWith('.md')) {
      if (EXCLUDED_FILES.includes(entry.name)) continue;

      const excluded = EXCLUDE_PATHS.find((prefix) => relPath.startsWith(prefix));
      if (excluded) continue;

      try {
        const raw = await fs.readFile(fullPath, 'utf-8');
        const { data: frontmatter } = matter(raw);
        results.push({
          relativePath: relPath,
          contentPath: fullPath,
          title: frontmatter.title || path.basename(entry.name, '.md'),
        });
      } catch (err) {
        console.error(`Error reading ${fullPath}: ${err.message}`);
      }
    }
  }

  return results;
}

/**
 * Build the file header
 */
function buildHeader() {
  const lines = [
    '# Neon Postgres Documentation',
    '',
    `> ${config.tagline}`,
    `> This file contains the full Neon documentation. For a table of contents, see ${BASE_URL}/docs/llms.txt`,
    '',
  ];
  return lines.join('\n');
}

/**
 * Main
 */
async function main() {
  const args = process.argv.slice(2);
  const dryRun = args.includes('--dry-run');

  const projectRoot = path.resolve(__dirname, '../..');
  const contentPath = path.join(projectRoot, 'content');
  const mdOutputDir = path.join(projectRoot, 'public/md');

  console.log('Scanning content directories for llms-full.txt...\n');

  // Determine which routes to include
  const includedRoutes = Object.entries(CONTENT_ROUTES).filter(
    ([route]) => !EXCLUDE_ROUTES.has(route)
  );

  console.log(`Excluded routes: ${Array.from(EXCLUDE_ROUTES).join(', ') || '(none)'}`);
  console.log(`Included routes: ${includedRoutes.map(([r]) => r).join(', ')}\n`);

  // Scan all included routes
  const allFiles = [];
  for (const [route, srcPath] of includedRoutes) {
    const fullDir = path.join(projectRoot, srcPath);
    const files = await scanDirectory(fullDir);

    // Map each file to its public/md/ path and URL
    for (const file of files) {
      const contentRelative = path.relative(contentPath, file.contentPath);
      const mdPath = path.join(mdOutputDir, contentRelative);

      // URL: content/docs/guides/prisma.md -> https://neon.com/docs/guides/prisma.md
      const url = `${BASE_URL}/${contentRelative}`;

      allFiles.push({
        ...file,
        mdPath,
        url,
        route,
        sortKey: contentRelative,
      });
    }

    console.log(`  ${route}: ${files.length} files`);
  }

  // Sort by directory path (natural grouping)
  allFiles.sort((a, b) => a.sortKey.localeCompare(b.sortKey));

  console.log(`\nTotal: ${allFiles.length} files to include\n`);

  if (dryRun) {
    console.log('--- Dry run: listing included files ---\n');
    let currentDir = '';
    for (const file of allFiles) {
      const dir = path.dirname(file.sortKey);
      if (dir !== currentDir) {
        currentDir = dir;
        console.log(`\n  [${dir}]`);
      }
      console.log(`    ${path.basename(file.relativePath)} — ${file.title}`);
    }
    console.log('\n--- End dry run ---');
    return;
  }

  // Read processed markdown and concatenate
  const parts = [buildHeader()];
  let readErrors = 0;

  for (const file of allFiles) {
    let content;
    try {
      content = await fs.readFile(file.mdPath, 'utf-8');
    } catch (err) {
      console.error(`Missing processed file: ${file.mdPath} (${err.code})`);
      readErrors++;
      continue;
    }

    const stripped = stripNavigationContext(content);
    parts.push(`--- DOCUMENT SOURCE: ${file.url} ---\n\n${stripped.trim()}\n`);
  }

  parts.push(`---\n\nFor all past changelog entries, see https://neon.com/docs/changelog.md\n`);

  if (readErrors > 0) {
    console.warn(`\nWarning: ${readErrors} file(s) missing from public/md/`);
  }

  const output = parts.join('\n');

  const outputPath = path.join(projectRoot, OUTPUT_PATH);
  await fs.mkdir(path.dirname(outputPath), { recursive: true });
  await fs.writeFile(outputPath, output);

  const sizeMB = (Buffer.byteLength(output, 'utf-8') / (1024 * 1024)).toFixed(2);
  console.log(`Written to ${outputPath} (${sizeMB} MB, ${allFiles.length - readErrors} docs)`);
}

main().catch((err) => {
  console.error('Error:', err);
  process.exit(1);
});
